CREATE TABLE trips (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, starts_at timestamptz, ends_at timestamptz, notes text, created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE trip_stops (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), trip_id uuid NOT NULL REFERENCES trips(id) ON DELETE CASCADE, school_id uuid REFERENCES schools(id) ON DELETE SET NULL, stop_order integer NOT NULL, notes text, UNIQUE(trip_id, stop_order));
CREATE TABLE visits (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), trip_id uuid REFERENCES trips(id) ON DELETE SET NULL, title text NOT NULL, type text NOT NULL, starts_at timestamptz NOT NULL, location text, goals text, notes text, created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX visits_starts_at_index ON visits(starts_at); CREATE TABLE visit_schools (visit_id uuid NOT NULL REFERENCES visits(id) ON DELETE CASCADE, school_id uuid NOT NULL REFERENCES schools(id) ON DELETE RESTRICT, UNIQUE(visit_id, school_id)); CREATE TABLE visit_directors (visit_id uuid NOT NULL REFERENCES visits(id) ON DELETE CASCADE, director_id uuid NOT NULL REFERENCES directors(id) ON DELETE RESTRICT, UNIQUE(visit_id, director_id)); CREATE TABLE visit_prospects (visit_id uuid NOT NULL REFERENCES visits(id) ON DELETE CASCADE, prospect_id uuid NOT NULL REFERENCES prospects(id) ON DELETE RESTRICT, UNIQUE(visit_id, prospect_id)); CREATE TABLE visit_outcomes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), visit_id uuid NOT NULL REFERENCES visits(id) ON DELETE CASCADE, outcome text NOT NULL, notes text, created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE mileage_entries (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), trip_id uuid REFERENCES trips(id) ON DELETE SET NULL, visit_id uuid REFERENCES visits(id) ON DELETE SET NULL, miles integer NOT NULL, notes text, created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE expenses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), trip_id uuid REFERENCES trips(id) ON DELETE SET NULL, visit_id uuid REFERENCES visits(id) ON DELETE SET NULL, amount_cents integer NOT NULL, category text NOT NULL, notes text, created_at timestamptz NOT NULL DEFAULT now());
